import { SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';
import { candidates } from './candidates';

function createEmptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

function cloneGrid(grid) {
	return grid.map((row) => row.slice());
}

function createEmptyGameView() {
	return {
		grid: createEmptyGrid(),
		invalidPositions: [],
		complete: false,
		won: false,
		canUndo: false,
		canRedo: false,
		exploring: false,
		exploreDepth: 0,
		exploreFailed: false,
		knownFailed: false,
		canCommitExplore: false,
		canDiscardExplore: false,
		nextHint: null,
		nextHintPreview: null,
		lastCandidateHint: null,
	};
}

function createGrid() {
	const grid = writable(createEmptyGrid());

	return {
		subscribe: grid.subscribe,

		generate(difficulty) {
			grid.set(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			grid.set(decodeSencode(sencode));
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

const gameView = writable(createEmptyGameView());
const userGridView = derived(gameView, ($gameView) => $gameView.grid);

function createUserGrid() {
	let puzzleGrid = createEmptyGrid();
	let game = createGame({ sudoku: createSudoku(puzzleGrid) });
	let lastCandidateHint = null;

	function hasPosition(pos) {
		return pos && Number.isInteger(pos.x) && Number.isInteger(pos.y);
	}

	function isEditableCell(pos) {
		return hasPosition(pos) && puzzleGrid[pos.y][pos.x] === 0;
	}

	function syncFromGame() {
		gameView.set({
			...game.getSnapshot(),
			lastCandidateHint,
		});
	}

	function rebuildGame(nextGrid) {
		puzzleGrid = cloneGrid(nextGrid);
		lastCandidateHint = null;
		candidates.clearAll();
		game = createGame({
			sudoku: createSudoku(puzzleGrid),
		});
		syncFromGame();
	}

	grid.subscribe(($grid) => {
		rebuildGame($grid);
	});

	return {
		subscribe: userGridView.subscribe,

		set(pos, value) {
			if (!isEditableCell(pos)) {
				return;
			}

			lastCandidateHint = null;
			game.guess({
				row: pos.y,
				col: pos.x,
				value,
			});
			syncFromGame();
		},

		showCandidates(pos) {
			if (!isEditableCell(pos)) {
				return;
			}

			lastCandidateHint = game.getCandidateHint({ row: pos.y, col: pos.x });
			candidates.replace(pos, lastCandidateHint.candidates);
			syncFromGame();
		},

		previewNextHint() {
			lastCandidateHint = null;
			syncFromGame();
		},

		applyNextHint() {
			const hint = game.getNextHint('value');
			if (!hint) {
				return;
			}

			hints.useHint();
			lastCandidateHint = hint;
			candidates.clear({ x: hint.col, y: hint.row });
			game.guess({
				row: hint.row,
				col: hint.col,
				value: hint.value,
			});
			syncFromGame();
		},

		undo() {
			lastCandidateHint = null;
			game.undo();
			syncFromGame();
		},

		redo() {
			lastCandidateHint = null;
			game.redo();
			syncFromGame();
		},

		enterExplore() {
			lastCandidateHint = null;
			if (game.enterExplore()) {
				syncFromGame();
			}
		},

		commitExplore() {
			lastCandidateHint = null;
			if (game.commitExplore()) {
				syncFromGame();
			}
		},

		discardExplore() {
			lastCandidateHint = null;
			if (game.discardExplore()) {
				candidates.clearAll();
				syncFromGame();
			}
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(
	gameView,
	($gameView) => $gameView.invalidPositions.map(({ row, col }) => `${col},${row}`),
	[],
);

export const canUndo = derived(gameView, ($gameView) => $gameView.canUndo, false);
export const canRedo = derived(gameView, ($gameView) => $gameView.canRedo, false);
export const won = derived(gameView, ($gameView) => $gameView.won, false);
export const exploring = derived(gameView, ($gameView) => $gameView.exploring, false);
export const exploreDepth = derived(gameView, ($gameView) => $gameView.exploreDepth, 0);
export const exploreFailed = derived(gameView, ($gameView) => $gameView.exploreFailed, false);
export const knownFailed = derived(gameView, ($gameView) => $gameView.knownFailed, false);
export const canCommitExplore = derived(gameView, ($gameView) => $gameView.canCommitExplore, false);
export const canDiscardExplore = derived(gameView, ($gameView) => $gameView.canDiscardExplore, false);
export const nextHint = derived(gameView, ($gameView) => $gameView.nextHint, null);
export const nextHintPreview = derived(gameView, ($gameView) => $gameView.nextHintPreview, null);
export const lastCandidateHint = derived(gameView, ($gameView) => $gameView.lastCandidateHint, null);
